import { forwardRef, useCallback, useRef, useState } from 'react';
import type { ListGroup } from '@o9ds/core';
import O9ActionMenu from '../ActionMenu/ActionMenu';
import type { MenuItemData } from '../ActionMenu/ActionMenu';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';
import type { MenuSearchProp } from '../../types/menu-search';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface O9DropdownIconButtonProps
  extends Omit<
    React.ButtonHTMLAttributes<HTMLButtonElement>,
    'disabled' | 'type' | 'onSelect'
  > {
  icon: string;
  tooltip: TooltipProp;
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  isCompact?: boolean;
  isDisabled?: boolean;
  isLoading?: boolean;
  items: MenuItemData[] | ListGroup<MenuItemData>[];
  /** Enable search with defaults (`true`) or pass a config object. */
  search?: MenuSearchProp;
  placement?: 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end';
  maxHeight?: string;
  hasGroupDividers?: boolean;
  closeOnSelect?: boolean;
  menuSize?: 'sm' | 'md';
  onSelect?: (item: MenuItemData, index: number) => boolean | void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onOpenChange?: (isOpen: boolean) => void;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9DropdownIconButton = forwardRef<
  HTMLButtonElement,
  O9DropdownIconButtonProps
>(
  function O9DropdownIconButton(
    {
      icon,
      tooltip,
      variant = 'primary',
      size = 'md',
      isCompact = false,
      isDisabled = false,
      isLoading = false,
      items,
      search,
      placement = 'bottom-end',
      maxHeight,
      hasGroupDividers = true,
      closeOnSelect = true,
      menuSize = 'md',
      className,
      onSelect,
      onOpen,
      onClose,
      onOpenChange,
      onClick,
      onFocus,
      onBlur,
      ...rest
    },
    ref,
  ) {
    // ── Open state (for caret rotation) ─────────────────────────────────
    const [isOpen, setIsOpen] = useState(false);

    // ── Open-change handler ─────────────────────────────────────────────
    const handleOpenChange = useCallback(
      (isOpen: boolean) => {
        setIsOpen(isOpen);
        onOpenChange?.(isOpen);
      },
      [onOpenChange],
    );

    // ── Tooltip ───────────────────────────────────────────────────────
    const tooltipContent = typeof tooltip === 'string' ? tooltip : tooltip.content;

    // ── Ref merging ─────────────────────────────────────────────────────
    const triggerRefInternal = useRef<HTMLButtonElement | null>(null);

    useTooltip({ triggerRef: triggerRefInternal, tooltip });

    const mergeRef = useCallback(
      (node: HTMLButtonElement | null) => {
        triggerRefInternal.current = node;
        if (typeof ref === 'function') {
          ref(node);
        } else if (ref) {
          (ref as React.MutableRefObject<HTMLButtonElement | null>).current =
            node;
        }
      },
      [ref],
    );

    // ── Trigger classes ─────────────────────────────────────────────────
    const triggerClasses = [
      'o9ds-dd-icon-btn',
      'o9ds-btn',
      `o9ds-btn--${variant}`,
      `o9ds-btn--${size}`,
      isCompact && 'o9ds-dd-icon-btn--compact',
      isOpen && 'open',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Trigger element ─────────────────────────────────────────────────
    const triggerElement = (
      <button
        ref={mergeRef}
        type="button"
        {...rest}
        className={triggerClasses}
        disabled={isDisabled}
        aria-label={tooltipContent}
        aria-busy={isLoading || undefined}
        onClick={onClick}
        onFocus={onFocus}
        onBlur={onBlur}
      >
        <span
          className={`o9ds-dd-icon-btn__icon o9con o9con-${icon}`}
          aria-hidden="true"
        />
        {!isCompact && (
          <span
            className="o9ds-dd-icon-btn__caret o9con o9con-angle-down"
            aria-hidden="true"
          />
        )}
      </button>
    );

    // ── Render ───────────────────────────────────────────────────────────
    return (
      <O9ActionMenu
        trigger={triggerElement}
        items={items}
        size={menuSize}
        placement={placement}
        search={search}
        maxHeight={maxHeight}
        hasGroupDividers={hasGroupDividers}
        closeOnSelect={closeOnSelect}
        isDisabled={isDisabled || isLoading}
        isLoading={false}
        onOpen={onOpen}
        onClose={onClose}
        onSelect={onSelect}
        onOpenChange={handleOpenChange}
      />
    );
  },
);

export default O9DropdownIconButton;
